import React, { useState } from "react";
import axios from "axios";
import { FaKey } from "react-icons/fa";
import { useNavigate } from "react-router-dom";
import "./verifyotp.css";

const VerifyOtpPage = () => {
  const [otp, setOtp] = useState("");
  const [message, setMessage] = useState("");
  const [error, setError] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);
  const navigate = useNavigate();

  const handleVerifyOtp = async (e) => {
    e.preventDefault();
    setMessage("");
    setError("");

    const email = localStorage.getItem("resetEmail");
    if (!email) {
      setError("Session expired. Please request a new OTP.");
      return;
    }

    if (!otp.trim()) {
      setError("OTP is required.");
      return;
    }

    try {
      setIsSubmitting(true);
      console.log("Verifying OTP...");

      const response = await axios.post("http://localhost:5000/api/auth/verify-otp", { email, otp });

      console.log("Response:", response.data);

      if (response.data.verified) {
        setMessage("OTP verified! Redirecting to reset password...");
        setTimeout(() => navigate("/reset-password"), 1000);
      } else {
        setError(response.data.message || "Invalid OTP.");
      }
    } catch (err) {
      setError("Error verifying OTP. Please try again.");
      console.error("OTP Verification Error:", err);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="verify-otp-container">
      <img src="/assets/ODCSE Logo.png" alt="Logo" className="logo" />

      <form onSubmit={handleVerifyOtp} className="verify-otp-form">
        <h2>Verify OTP</h2>
        <p>Enter the OTP sent to your registered email</p>

        <div className="input-group">
          <FaKey className="icon" />
          <input
            type="text"
            placeholder="Enter OTP"
            value={otp}
            onChange={(e) => setOtp(e.target.value)}
            required
            disabled={isSubmitting}
          />
        </div>

        <button type="submit" className="verify-otp-button" disabled={isSubmitting}>
          {isSubmitting ? "Verifying..." : "Verify OTP"}
        </button>

        <div className="message-container">
          {message && <p className="success-message">{message}</p>}
          {error && <p className="error-message">{error}</p>}
        </div>
      </form>

      <div className="back-to-login">
        <button onClick={() => navigate("/forgot-password")} className="back-button">Back</button>
      </div>
    </div>
  );
};

export default VerifyOtpPage;
